queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?role_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:building_role_id ?cg . ?child a :Building_Roles ; p:role_id ?cg . ?l p:construction_company_id ?pg . ?parent a :Construction_Companies ; p:id ?pg . } GROUP BY ?child }
  ?child p:role_value ?role_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Construction_Companies } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?company_name ?role_value WHERE {
  ?construction_companies_building_roles a :Construction_Companies_Building_Roles .
  ?building_roles a :Building_Roles .
  ?construction_companies_building_roles p:hasBuilding_Roles ?building_roles .
  ?construction_companies a :Construction_Companies .
  ?construction_companies_building_roles p:hasConstruction_Companies ?construction_companies .
  ?construction_companies p:company_name ?company_name .
  ?building_roles p:role_value ?role_value .
} }
  collective: { SELECT ?role_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:building_role_id ?cg . ?child a :Building_Roles ; p:role_id ?cg . ?l p:construction_company_id ?pg . ?parent a :Construction_Companies ; p:id ?pg . } GROUP BY ?child }
  ?child p:role_value ?role_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Construction_Companies } }
  FILTER(?nf = ?total)
} }
}
